mapper.select:
SELECT * FROM ( SELECT cl.commit_id, cl.project_id, cl.issue_id, cl.branch_name, cl.commit_hash, cl.commit_message, cl.author_name, cl.author_email, cl.committed_at, cl.created_at, i.title AS issue_title, i.issue_status_id, i.progress_rate, ROW_NUMBER() OVER (ORDER BY cl.committed_at DESC) AS rnum FROM commit_log cl LEFT JOIN issue i ON i.issue_id = cl.issue_id WHERE cl.project_id = #{projectId}
AND cl.branch_name = #{branchName}
) WHERE rnum > #{offset} AND rnum <= #{offset} + #{limit}

SELECT COUNT(*)
FROM commit_log
WHERE project_id = #{projectId}

	AND branch_name = #{branchName}

SELECT * FROM ( SELECT cl.commit_id, cl.project_id, cl.issue_id, cl.branch_name, cl.commit_hash, cl.commit_message, cl.author_name, cl.author_email, cl.committed_at, cl.created_at, i.title AS issue_title, i.issue_status_id, i.progress_rate FROM commit_log cl LEFT JOIN issue i ON i.issue_id = cl.issue_id WHERE cl.commit_hash = #{commitHash}
AND cl.branch_name = #{branchName}
ORDER BY cl.committed_at DESC ) WHERE ROWNUM = 1

